import * as React from "react";
import * as ReactDom from "react-dom";
import { BaseClientSideWebPart } from "@microsoft/sp-webpart-base";
import { HbCentralHomepageHost } from "../../runtime/HbCentralHomepageHost";
import "../../runtime/homepageHardening.css";

export default class HbCentralHomepageWebPart extends BaseClientSideWebPart<Record<string, never>> {
  public render(): void {
    ReactDom.render(
      <React.StrictMode>
        <HbCentralHomepageHost />
      </React.StrictMode>,
      this.domElement,
    );
  }

  protected onDispose(): void {
    ReactDom.unmountComponentAtNode(this.domElement);
  }
}
